Actionscript.script:
stop();

var mainTimeline:MovieClip = MovieClip(this.root);

if (mainTimeline.audioMute === undefined) {
	mainTimeline.audioMute = false;
	mainTimeline.previousVolume = 1.0;

	var initTransform:SoundTransform = new SoundTransform();
	initTransform.volume = 1.0;
	SoundMixer.soundTransform = initTransform;
}

if (!mainTimeline.audioMute) {
    AudioBtn.gotoAndStop(1);
} else {
    AudioBtn.gotoAndStop(2);
}

AudioBtn.removeEventListener(MouseEvent.CLICK, onAudioToggle);
AudioBtn.addEventListener(MouseEvent.CLICK, onAudioToggle);

function onAudioToggle(e:MouseEvent):void {
    var currentTransform:SoundTransform = SoundMixer.soundTransform;

    if (!mainTimeline.audioMute) {
        mainTimeline.previousVolume = currentTransform.volume;
        currentTransform.volume = 0;
        mainTimeline.audioMute = true;
        AudioBtn.gotoAndStop(2);
    } else {
        currentTransform.volume = mainTimeline.previousVolume;
        mainTimeline.audioMute = false;
        AudioBtn.gotoAndStop(1);
    }
    SoundMixer.soundTransform = currentTransform;
}
